const VALUE_PATTERNS = [
  /^[-+]?\d*\.?\d+(px|em|rem|vh|vw|cm|mm|Q|in|pt|pc|ex|ch|lh|vmin|vmax|%)$/i,
  /^[-+]?\d*\.?\d+%$/,
  /^url\(['"]?(.*?)['"]?\)$/,
  /^[-+]?\d*\.?\d+(deg|grad|rad|turn)$/,
  /^[-+]?\d*\.?\d+(s|ms)$/,
  /^(inherit|initial|unset)$/,
  /^var\(--\S+\)$/,
  /^(left|right|center|justify|start|end)$/,
  /^(baseline|sub|super|top|text-top|middle|bottom|text-bottom)$/,
  /^(flex-start|flex-end|center|space-between|space-around|space-evenly)$/,
  /^(flex-start|flex-end|center|baseline|stretch)$/,
  /^(start|end|center|stretch)$/,
  /^(left|right|none)$/,
  /^(row|column|column-reverse|row-reverse)$/,
  /^(cover|contain|stretch)$/,
  /^(static|relative|fixed|absolute|sticky)$/,
  /^(block|flex|grid)$/,
  /^[-+]?\d+$/,
  /^auto$/,
  /^span \d+$/,
  /!important$/,
  /^#([0-9a-f]{3}|[0-9a-f]{6})$/i,
  /^rgb\(\s?(\d{1,3}),\s?(\d{1,3}),\s?(\d{1,3})\s?\)$/i,
  /^.*\(.+\).*$/,
  /^[-+]?\d*\.?\d+(px|em|rem|vh|vw|cm|mm|Q|in|pt|pc|ex|ch|lh|vmin|vmax|%)\s(solid|dashed|dotted|double|groove|ridge|inset|outset|none|hidden)?\s?(#[0-9a-fA-F]{3}(?:[0-9a-fA-F]{3})?|rgba?\((-?\d+%?[,\s]+){2,3}\s*[\d\.]+%?\)|black|white|blue|green|red|yellow|purple|cyan|aqua|lime|maroon|navy|olive|silver|teal|gray|grey|fuchsia|)?$/i,
];

const SIZING_KEYS = ['width', 'height', 'min-width', 'max-width', 'min-height', 'max-height'];

/** Returns `true` when `value` is a valid CSS value for the given property. */
export const isCssValue = (value: unknown, key: string): boolean => {
  if (typeof value === 'string' && isThemeToken(value)) return true;

  // Native CSS.supports check
  if (typeof value === 'string' && value.includes('!important')) {
    if (CSS.supports(key, value.replace('!important', ''))) return true;
  } else {
    if (CSS.supports(key, value as string)) return true;
  }

  if (key === 'col-offset') return false;

  if (
      (value === 'full' || value === 'screen') &&
      SIZING_KEYS.includes(key)
  ) {
    return true;
  }

  if (CSS_COLOR_NAMES.has(value as string)) return true;

  for (const pattern of VALUE_PATTERNS) {
    if (pattern.test(value as string)) return true;
  }

  return false;
};
